- (void)wb_showBadgeOnItemIndex:(int)index {
    [self wb_removeBadgeOnItemIndex:index];
    UIView *bview = [[UIView alloc]init];
    bview.tag = 888 + index;
    bview.layer.cornerRadius = 3;
    bview.clipsToBounds = YES;
    bview.backgroundColor = [UIColor redColor];
    CGRect tabFram = self.frame;

    float percentX = (index + 0.55) / self.items.count;
    CGFloat x = ceilf(percentX * tabFram.size.width);
    CGFloat y = ceilf(0.07 * tabFram.size.height);
    bview.frame = CGRectMake(x, y, 6, 6);
    [self addSubview:bview];
    [self bringSubviewToFront:bview];
}

- (void)wb_hideBadgeOnItemIndex:(int)index {
    [self wb_removeBadgeOnItemIndex:index];
}

- (void)wb_removeBadgeOnItemIndex:(int)index {
    for (UIView *subView in self.subviews) {
        if (subView.tag == 888 + index) {
            [subView removeFromSuperview];
        }
    }
}

