// 三列等宽布局：根据可用宽度与列间距等分计算单元格宽度，保证所有设备上都显示为 3 列
- (CGSize)collectionView:(UICollectionView *)collectionView layout:(UICollectionViewLayout *)collectionViewLayout sizeForItemAtIndexPath:(NSIndexPath *)indexPath {
    UICollectionViewFlowLayout *flowLayout = (UICollectionViewFlowLayout *)collectionViewLayout;
    UIEdgeInsets insets = [self collectionView:collectionView layout:collectionViewLayout insetForSectionAtIndex:indexPath.section];
    CGFloat totalWidth = collectionView.bounds.size.width;
    CGFloat spacing = flowLayout.minimumInteritemSpacing;
    NSInteger numberOfColumns = 3;
    CGFloat availableWidth = totalWidth - insets.left - insets.right - spacing * (numberOfColumns - 1);
    CGFloat itemWidth = floor(availableWidth / numberOfColumns);
    CGFloat itemHeight = ZOOM(56);
    return CGSizeMake(itemWidth, itemHeight);
}


