- (void)loadMyPromos {
//    [WBProgressHUD showPlainLoading];
    [[WBNetworkManager defaultManager] requestAllMyPromoCodeWithCallback:^(NSArray<WBPromoModel *> * _Nullable promoModels, NSError * _Nullable error) {
        if (error) {
            [WBProgressHUD dismiss];
            [WBProgressHUD showPlainNetworkError];
            return;
        }
        WBSettingManager.sharedManager.Pomosize = promoModels.count;
        // 对 promoModels 数组进行排序，让未领取的优惠券始终处于卡包的最上面
        NSArray<WBPromoModel *> *sortedPromoModels = [promoModels sortedArrayUsingComparator:^NSComparisonResult(WBPromoModel *promo1, WBPromoModel *promo2) {
            if (promo1.unclaimed && !promo2.unclaimed) {
                return NSOrderedAscending;
            } else if (!promo1.unclaimed && promo2.unclaimed) {
                return NSOrderedDescending;
            }
            return NSOrderedSame;
        }];

        [self parseAvailableAndUnavailablePromos:sortedPromoModels];
        [self.view removeAllSubviews];
        [self addAllSubviews];
        [self addAllConstraints];
        [self.tableView reloadData];
        [WBProgressHUD dismiss];
    }];
