    if (![allPromoModels count]) return;
    NSMutableArray<WBPromoModel *> *availablePromoModels = [NSMutableArray arrayWithCapacity:[allPromoModels count]];
    NSMutableArray<WBPromoModel *> *unavailablePromoModels = [NSMutableArray arrayWithCapacity:[allPromoModels count]];
    for (WBPromoModel *promoModel in allPromoModels) {
        if (![WBVipViewController checkIfCouldUsePromo:self.productModel]) {
            [unavailablePromoModels addObject:promoModel];
            continue;
        } else {
            if (promoModel.expired || promoModel.useDate != nil || (self.productModel && [self.productModel.price floatValue] < promoModel.minCharge)) {
                [unavailablePromoModels addObject:promoModel];
            } else {
                [availablePromoModels addObject:promoModel];
            }
        }
    }
    self.availablePromoModels = [availablePromoModels copy];
    self.unavailablePromoModels = [unavailablePromoModels copy];
    [self parseSelectedPromos];
}

